async function loadAllRegexScripts3(ctx) {
  const out = [];
  let offset = 0;
  for (;; ) {
    const res = await ctx.spindle.regex_scripts.list({
      scope: "character",
      scopeId: ctx.characterId,
      userId: ctx.userId,
      limit: 200,
      offset
    });
    out.push(...res.data);
    if (out.length >= res.total || res.data.length === 0)
      break;
    offset += res.data.length;
  }
  return out;
}
