// src/agent/tools/_context.ts
class RecentReadsCache {
  entries = new Map;
  record(key, hash2) {
    this.entries.set(key, { ts: Date.now(), hash: hash2 ?? null });
  }
  has(key) {
    return this.entries.has(key);
  }
  ageMs(key) {
    const t = this.entries.get(key);
    return t === undefined ? null : Date.now() - t.ts;
  }
  getHash(key) {
    return this.entries.get(key)?.hash ?? null;
  }
  updateHash(key, hash2) {
    const existing = this.entries.get(key);
    if (!existing)
      return;
    this.entries.set(key, { ts: existing.ts, hash: hash2 });
  }
  forget(key) {
    this.entries.delete(key);
  }
}

// src/agent/tools.ts
init__registry();
function makeInitialToolSchemas() {
  return registry2.schemas().filter((s) => !isDeferredTool(s.name));
}
function makeDeferredToolSchemaMap() {
  const out = {};
  for (const name of listDeferredToolNames()) {
    const s = registry2.schemaFor(name);
    if (s)
      out[name] = s;
  }
  return out;
}
function makeToolDispatch() {
  const dispatch = {};
  for (const tool of registry2.list()) {
    dispatch[tool.name] = async (args, ctx) => {
      const parsed = tool.inputSchema.safeParse(args);
      if (!parsed.success) {
        return `Error: [INVALID_INPUT] invalid input for tool '${tool.name}':
${formatZodError(parsed.error)}`;
      }
      const ctxWithDispatch = { ...ctx, __dispatch: dispatch };
      if (tool.validateInput) {
        const v = await tool.validateInput(parsed.data, ctxWithDispatch);
        if (!v.result)
          return `Error: [${v.errorCode}] ${v.message}`;
      }
      const r = await tool.execute(parsed.data, ctxWithDispatch);
      return r.content;
    };
  }
  return dispatch;
}

